             foreach (var course in allCourses)
             {
                 viewModel.Add(new AssignedCourseData
                 {
                     CourseID = course.CourseID,
                     Title = course.Title,
                     Assigned = instructorCourses.Contains(course.CourseID)
                 });
             }
             ViewBag.Courses = viewModel;
         }

