using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests.Helpers;

internal static class TestHelpers
{
    /// <summary>
    /// Creates a fresh in-memory SchoolContext with a unique database name.
    /// </summary>
    public static SchoolContext CreateInMemoryContext()
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: Guid.NewGuid().ToString())
            .Options;
        return new SchoolContext(options);
    }

    /// <summary>
    /// Drains the static NotificationService queue to ensure test isolation.
    /// </summary>
    public static void DrainNotificationQueue()
    {
        using var service = new NotificationService();
        while (service.ReceiveNotification() != null) { }
    }

    /// <summary>
    /// Seeds a context with sample students.
    /// </summary>
    public static void SeedStudents(SchoolContext context)
    {
        context.Students.AddRange(
            new Student
            {
                ID = 1,
                LastName = "Alexander",
                FirstMidName = "Carson",
                EnrollmentDate = new DateTime(2020, 9, 1)
            },
            new Student
            {
                ID = 2,
                LastName = "Alonso",
                FirstMidName = "Meredith",
                EnrollmentDate = new DateTime(2021, 9, 1)
            },
            new Student
            {
                ID = 3,
                LastName = "Zheng",
                FirstMidName = "Roger",
                EnrollmentDate = new DateTime(2019, 9, 1)
            }
        );
        context.SaveChanges();
    }

    /// <summary>
    /// Seeds a context with sample departments and courses.
    /// </summary>
    public static void SeedDepartmentsAndCourses(SchoolContext context)
    {
        var dept = new Department
        {
            DepartmentID = 1,
            Name = "Engineering",
            Budget = 350000m,
            StartDate = new DateTime(2010, 9, 1)
        };
        context.Departments.Add(dept);
        context.SaveChanges();

        context.Courses.AddRange(
            new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
            new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 1 },
            new Course { CourseID = 1045, Title = "Calculus", Credits = 4, DepartmentID = 1 }
        );
        context.SaveChanges();
    }

    /// <summary>
    /// Seeds a context with sample instructors including office assignments and course assignments.
    /// </summary>
    public static void SeedInstructors(SchoolContext context)
    {
        var instructor1 = new Instructor
        {
            ID = 10,
            LastName = "Fakhouri",
            FirstMidName = "Fadi",
            HireDate = new DateTime(2002, 7, 6),
            CourseAssignments = new List<CourseAssignment>(),
            OfficeAssignment = new OfficeAssignment { InstructorID = 10, Location = "Smith 17" }
        };
        var instructor2 = new Instructor
        {
            ID = 11,
            LastName = "Harui",
            FirstMidName = "Roger",
            HireDate = new DateTime(1998, 7, 1),
            CourseAssignments = new List<CourseAssignment>()
        };
        context.Instructors.AddRange(instructor1, instructor2);
        context.SaveChanges();
    }
}

