using ContosoUniversity.Models;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Models;

[TestClass]
public sealed class PersonTests
{
    [TestMethod]
    public void FullName_WithLastAndFirstName_ReturnsCommaSeparated()
    {
        // Arrange - use Student as concrete implementation of Person
        var student = new Student
        {
            LastName = "Smith",
            FirstMidName = "John"
        };

        // Act
        var result = student.FullName;

        // Assert
        Assert.AreEqual("Smith, John", result);
    }

    [TestMethod]
    public void FullName_WithSingleCharNames_ReturnsCommaSeparated()
    {
        // Arrange
        var student = new Student
        {
            LastName = "A",
            FirstMidName = "B"
        };

        // Act
        var result = student.FullName;

        // Assert
        Assert.AreEqual("A, B", result);
    }

    [TestMethod]
    public void FullName_WithLongNames_ReturnsCommaSeparated()
    {
        // Arrange
        var instructor = new Instructor
        {
            LastName = "Abercrombie",
            FirstMidName = "Alexander"
        };

        // Act
        var result = instructor.FullName;

        // Assert
        Assert.AreEqual("Abercrombie, Alexander", result);
    }

    [TestMethod]
    public void FullName_InstructorVsStudent_BothComputeCorrectly()
    {
        // Arrange
        var student = new Student { LastName = "Doe", FirstMidName = "Jane" };
        var instructor = new Instructor { LastName = "Doe", FirstMidName = "Jane" };

        // Act & Assert
        Assert.AreEqual(student.FullName, instructor.FullName);
        Assert.AreEqual("Doe, Jane", student.FullName);
    }
}

using ContosoUniversity.Models;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Models;

[TestClass]
public sealed class ErrorViewModelTests
{
    [TestMethod]
    public void ShowRequestId_WhenRequestIdIsNotEmpty_ReturnsTrue()
    {
        // Arrange
        var model = new ErrorViewModel { RequestId = "abc123" };

        // Act
        var result = model.ShowRequestId;

        // Assert
        Assert.IsTrue(result);
    }

    [TestMethod]
    public void ShowRequestId_WhenRequestIdIsNull_ReturnsFalse()
    {
        // Arrange
        var model = new ErrorViewModel { RequestId = null };

        // Act
        var result = model.ShowRequestId;

        // Assert
        Assert.IsFalse(result);
    }

    [TestMethod]
    public void ShowRequestId_WhenRequestIdIsEmpty_ReturnsFalse()
    {
        // Arrange
        var model = new ErrorViewModel { RequestId = string.Empty };

        // Act
        var result = model.ShowRequestId;

        // Assert
        Assert.IsFalse(result);
    }

    [TestMethod]
    public void ShowRequestId_WhenRequestIdIsWhitespace_ReturnsTrue()
    {
        // Arrange - whitespace is not null or empty
        var model = new ErrorViewModel { RequestId = "   " };

        // Act
        var result = model.ShowRequestId;

        // Assert - string.IsNullOrEmpty does not treat whitespace as empty
        Assert.IsTrue(result);
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    public void Constructor_SetsPageIndex()
    {
        // Arrange
        var items = new List<string> { "a", "b", "c" };

        // Act
        var list = new PaginatedList<string>(items, 10, 2, 5);

        // Assert
        Assert.AreEqual(2, list.PageIndex);
    }

    [TestMethod]
    public void Constructor_CalculatesTotalPagesCorrectly()
    {
        // Arrange - 10 items, page size 3 → ceil(10/3) = 4
        var items = new List<string> { "a", "b", "c" };

        // Act
        var list = new PaginatedList<string>(items, 10, 1, 3);

        // Assert
        Assert.AreEqual(4, list.TotalPages);
    }

    [TestMethod]
    public void Constructor_TotalPagesExactDivision()
    {
        // Arrange - 10 items, page size 5 → ceil(10/5) = 2
        var items = new List<string> { "a", "b" };

        // Act
        var list = new PaginatedList<string>(items, 10, 1, 5);

        // Assert
        Assert.AreEqual(2, list.TotalPages);
    }

    [TestMethod]
    public void Constructor_AddsItemsToList()
    {
        // Arrange
        var items = new List<int> { 1, 2, 3 };

        // Act
        var list = new PaginatedList<int>(items, 3, 1, 10);

        // Assert
        Assert.AreEqual(3, list.Count);
        Assert.AreEqual(1, list[0]);
        Assert.AreEqual(2, list[1]);
        Assert.AreEqual(3, list[2]);
    }

    [TestMethod]
    public void HasPreviousPage_OnFirstPage_ReturnsFalse()
    {
        // Arrange
        var list = new PaginatedList<string>(new List<string>(), 10, 1, 5);

        // Act & Assert
        Assert.IsFalse(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_OnSecondPage_ReturnsTrue()
    {
        // Arrange
        var list = new PaginatedList<string>(new List<string>(), 10, 2, 5);

        // Act & Assert
        Assert.IsTrue(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasNextPage_OnLastPage_ReturnsFalse()
    {
        // Arrange - 10 items, page size 5 → 2 pages, on page 2
        var list = new PaginatedList<string>(new List<string>(), 10, 2, 5);

        // Act & Assert
        Assert.IsFalse(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_NotOnLastPage_ReturnsTrue()
    {
        // Arrange - 10 items, page size 5 → 2 pages, on page 1
        var list = new PaginatedList<string>(new List<string>(), 10, 1, 5);

        // Act & Assert
        Assert.IsTrue(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_SinglePage_ReturnsFalse()
    {
        // Arrange - 3 items, page size 5 → 1 page
        var list = new PaginatedList<string>(new List<string>(), 3, 1, 5);

        // Act & Assert
        Assert.IsFalse(list.HasNextPage);
    }

    [TestMethod]
    public void Create_ReturnsCorrectPageOfItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act - page 2, page size 10
        var result = PaginatedList<int>.Create(source, 2, 10);

        // Assert
        Assert.AreEqual(2, result.PageIndex);
        Assert.AreEqual(3, result.TotalPages); // ceil(25/10) = 3
        Assert.AreEqual(10, result.Count); // 10 items on page 2
        Assert.AreEqual(11, result[0]); // first item on page 2
        Assert.AreEqual(20, result[9]); // last item on page 2
