using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;
using System.Linq;
using System.Net;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class StudentsControllerTests
{
    private SchoolContext _context;
    private StudentsController _controller;

    [TestInitialize]
    public void Setup()
    {
        TestHelpers.DrainNotificationQueue();
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new StudentsController(_context);
        SeedStudents();
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
        TestHelpers.DrainNotificationQueue();
    }

    private void SeedStudents()
    {
        _context.Students.AddRange(
            new Student { ID = 1, LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = new DateTime(2020, 9, 1) },
            new Student { ID = 2, LastName = "Alonso", FirstMidName = "Meredith", EnrollmentDate = new DateTime(2021, 9, 1) },
            new Student { ID = 3, LastName = "Zheng", FirstMidName = "Roger", EnrollmentDate = new DateTime(2019, 9, 1) },
            new Student { ID = 4, LastName = "Baker", FirstMidName = "Ann", EnrollmentDate = new DateTime(2020, 1, 15) }
        );
        _context.SaveChanges();
    }

    // ========== Index Tests ==========

    [TestMethod]
    public void Index_DefaultSort_ReturnsStudentsOrderedByLastNameAsc()
    {
        // Act
        var result = _controller.Index(null, null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(4, model.Count);
        Assert.AreEqual("Alexander", model[0].LastName);
        Assert.AreEqual("Alonso", model[1].LastName);
        Assert.AreEqual("Baker", model[2].LastName);
        Assert.AreEqual("Zheng", model[3].LastName);
    }

    [TestMethod]
    public void Index_NameDescSort_ReturnsStudentsOrderedByLastNameDesc()
    {
        // Act
        var result = _controller.Index("name_desc", null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Zheng", model[0].LastName);
        Assert.AreEqual("Baker", model[1].LastName);
        Assert.AreEqual("Alonso", model[2].LastName);
        Assert.AreEqual("Alexander", model[3].LastName);
    }

    [TestMethod]
    public void Index_DateSort_ReturnsStudentsOrderedByEnrollmentDateAsc()
    {
        // Act
        var result = _controller.Index("Date", null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Zheng", model[0].LastName); // 2019
        Assert.AreEqual("Baker", model[1].LastName); // 2020-01
        Assert.AreEqual("Alexander", model[2].LastName); // 2020-09
        Assert.AreEqual("Alonso", model[3].LastName); // 2021
    }

    [TestMethod]
    public void Index_DateDescSort_ReturnsStudentsOrderedByEnrollmentDateDesc()
    {
        // Act
        var result = _controller.Index("date_desc", null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Alonso", model[0].LastName); // 2021
        Assert.AreEqual("Alexander", model[1].LastName); // 2020-09
        Assert.AreEqual("Baker", model[2].LastName); // 2020-01
        Assert.AreEqual("Zheng", model[3].LastName); // 2019
    }

    [TestMethod]
    public void Index_SearchByLastName_FiltersResults()
    {
        // Act
        var result = _controller.Index(null, null, "Al", null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count);
        Assert.IsTrue(model.All(s => s.LastName.Contains("Al") || s.FirstMidName.Contains("Al")));
    }

    [TestMethod]
    public void Index_SearchByFirstName_FiltersResults()
    {
        // Act
        var result = _controller.Index(null, null, "Carson", null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Carson", model[0].FirstMidName);
    }

    [TestMethod]
    public void Index_SearchNoMatch_ReturnsEmptyList()
    {
        // Act
        var result = _controller.Index(null, null, "ZZZZZ", null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(0, model.Count);
    }

    [TestMethod]
    public void Index_NewSearchString_ResetsPageTo1()
    {
        // Act - searchString is not null, so page should be reset to 1
        var result = _controller.Index(null, null, "Al", 3) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.PageIndex);
    }

    [TestMethod]
    public void Index_NullSearchString_UsesCurrentFilter()
    {
        // Act - searchString is null, currentFilter is used
        var result = _controller.Index(null, "Al", null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count); // "Al" matches Alexander and Alonso
    }

    [TestMethod]
    public void Index_SetsViewBagSortParams()
    {
        // Act
        _controller.Index(null, null, null, null);

        // Assert - default sort: NameSortParm = "name_desc", DateSortParm = "Date"
        Assert.AreEqual("name_desc", _controller.ViewBag.NameSortParm);
        Assert.AreEqual("Date", _controller.ViewBag.DateSortParm);
    }

    [TestMethod]
    public void Index_NameDescSort_SetsNameSortParmToEmpty()
    {
        // Act
        _controller.Index("name_desc", null, null, null);

        // Assert - sortOrder is not empty, so NameSortParm = ""
        Assert.AreEqual("", _controller.ViewBag.NameSortParm);
    }

    [TestMethod]
    public void Index_DateSort_SetsDateSortParmToDateDesc()
    {
        // Act
        _controller.Index("Date", null, null, null);

        // Assert
        Assert.AreEqual("date_desc", _controller.ViewBag.DateSortParm);
    }

    [TestMethod]
    public void Index_SetsCurrentSort()
    {
        // Act
        _controller.Index("name_desc", null, null, null);

        // Assert
        Assert.AreEqual("name_desc", _controller.ViewBag.CurrentSort);
    }

    [TestMethod]
    public void Index_SetsCurrentFilter()
    {
        // Act
        _controller.Index(null, null, "test", null);

        // Assert
        Assert.AreEqual("test", _controller.ViewBag.CurrentFilter);
    }

    // ========== Details Tests ==========

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null);

        // Assert
        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithStudent()
    {
        // Act
        var result = _controller.Details(1) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual("Alexander", model.LastName);
        Assert.AreEqual("Carson", model.FirstMidName);
    }

    // ========== Create GET Tests ==========

    [TestMethod]
    public void Create_Get_ReturnsViewWithStudentDefaultDate()
    {
        // Act
        var result = _controller.Create() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(DateTime.Today, model.EnrollmentDate);
    }

    // ========== Create POST Tests ==========

    [TestMethod]
    public void CreatePost_ValidStudent_RedirectsToIndex()
    {
        // Arrange
        var student = new Student
        {
            LastName = "NewStudent",
            FirstMidName = "Test",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };

        // Act
        var result = _controller.Create(student) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);

        // Verify the student was actually saved
        Assert.AreEqual(5, _context.Students.Count());
        var saved = _context.Students.Single(s => s.LastName == "NewStudent");
        Assert.AreEqual("Test", saved.FirstMidName);
    }

    [TestMethod]
    public void CreatePost_MinValueDate_AddsModelError()
    {
        // Arrange
        var student = new Student
        {
            LastName = "Test",
            FirstMidName = "Student",
            EnrollmentDate = DateTime.MinValue
        };

        // Act
        var result = _controller.Create(student) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsFalse(_controller.ModelState.IsValid);
        Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    [TestMethod]
    public void CreatePost_DefaultDateTime_AddsModelError()
    {
        // Arrange
        var student = new Student
        {
            LastName = "Test",
            FirstMidName = "Student",
            EnrollmentDate = default(DateTime)
        };

        // Act
        var result = _controller.Create(student) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsFalse(_controller.ModelState.IsValid);
    }

    [TestMethod]
    public void CreatePost_DateBefore1753_AddsModelError()
    {
        // Arrange
        var student = new Student
        {
            LastName = "Test",
            FirstMidName = "Student",
            EnrollmentDate = new DateTime(1752, 12, 31)
        };

        // Act
        var result = _controller.Create(student) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsFalse(_controller.ModelState.IsValid);
        Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    [TestMethod]
    public void CreatePost_InvalidModelState_ReturnsView()
    {
        // Arrange
        _controller.ModelState.AddModelError("LastName", "Required");
        var student = new Student
        {
            LastName = "",
            FirstMidName = "Test",
            EnrollmentDate = new DateTime(2023, 1, 1)
        };

        // Act
        var result = _controller.Create(student) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(student, result.Model);
    }

    // ========== Edit GET Tests ==========

    [TestMethod]
    public void EditGet_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Edit(null);

        // Assert
        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
    }

    [TestMethod]
    public void EditGet_ValidId_ReturnsViewWithStudent()
    {
        // Act
        var result = _controller.Edit(1) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual("Alexander", model.LastName);
    }

    [TestMethod]
    public void EditGet_InvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Edit(999);

        // Assert
        Assert.IsInstanceOfType(result, typeof(NotFoundResult));
    }

    // ========== Edit POST Tests ==========

    [TestMethod]
    public void EditPost_ValidStudent_RedirectsToIndex()
    {
        // Arrange
        var student = new Student
        {
            ID = 1,
            LastName = "UpdatedName",
            FirstMidName = "Carson",
