        Assert.IsFalse(_controller.ModelState.IsValid);
    }

    [TestMethod]
    public void EditPost_InvalidModelState_ReturnsView()
    {
        // Arrange
        _controller.ModelState.AddModelError("LastName", "Required");
        var student = new Student
        {
            ID = 1,
            LastName = "",
            FirstMidName = "Carson",
            EnrollmentDate = new DateTime(2020, 9, 1)
        };

        // Act
        var result = _controller.Edit(student) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    // ========== Delete GET Tests ==========

    [TestMethod]
    public void DeleteGet_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Delete(null);

        // Assert
        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
    }

    [TestMethod]
    public void DeleteGet_ValidId_ReturnsViewWithStudent()
    {
        // Act
        var result = _controller.Delete(1) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual("Alexander", model.LastName);
    }

    [TestMethod]
    public void DeleteGet_InvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Delete(999);

        // Assert
        Assert.IsInstanceOfType(result, typeof(NotFoundResult));
    }

    // ========== DeleteConfirmed Tests ==========

    [TestMethod]
    public void DeleteConfirmed_ValidId_RemovesStudentAndRedirects()
    {
        // Arrange
        var initialCount = _context.Students.Count();

        // Act
        var result = _controller.DeleteConfirmed(1) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(initialCount - 1, _context.Students.Count());
        Assert.IsNull(_context.Students.Find(1));
    }

    [TestMethod]
    public void CreatePost_ValidStudent_SendsNotification()
    {
        // Arrange
        var student = new Student
        {
            LastName = "NotifyTest",
            FirstMidName = "Student",
            EnrollmentDate = new DateTime(2023, 1, 1)
        };

        // Act
        _controller.Create(student);

        // Assert - notification was queued (drain and check)
        var service = new ContosoUniversity.Services.NotificationService();
        var notifications = new System.Collections.Generic.List<Notification>();
        Notification n;
        while ((n = service.ReceiveNotification()) != null) notifications.Add(n);
        Assert.IsTrue(notifications.Any(x => x.EntityType == "Student" && x.Operation == "CREATE"));
