using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.Rendering;
using Microsoft.Extensions.Logging;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Moq;
using System;
using System.IO;
using System.Linq;
using System.Net;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class CoursesControllerTests
{
    private SchoolContext _context;
    private CoursesController _controller;
    private Mock<IWebHostEnvironment> _envMock;
    private Mock<ILogger<CoursesController>> _loggerMock;
    private string _tempDir;

    [TestInitialize]
    public void Setup()
    {
        TestHelpers.DrainNotificationQueue();
        _context = TestHelpers.CreateInMemoryContext();

        // Create a temp directory for file upload tests
        _tempDir = Path.Combine(Path.GetTempPath(), "CoursesTest_" + Guid.NewGuid().ToString("N"));
        Directory.CreateDirectory(_tempDir);

        _envMock = new Mock<IWebHostEnvironment>();
        _envMock.Setup(e => e.WebRootPath).Returns(_tempDir);
        _envMock.Setup(e => e.ContentRootPath).Returns(_tempDir);

        _loggerMock = new Mock<ILogger<CoursesController>>();

        _controller = new CoursesController(_context, _envMock.Object, _loggerMock.Object);

        SeedData();
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
        if (Directory.Exists(_tempDir))
        {
            try { Directory.Delete(_tempDir, true); } catch { }
        }
        TestHelpers.DrainNotificationQueue();
    }

    private void SeedData()
    {
        var dept = new Department
        {
            DepartmentID = 1,
            Name = "Engineering",
            Budget = 350000m,
            StartDate = new DateTime(2010, 9, 1)
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        _context.Courses.AddRange(
            new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
            new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 1 }
        );
        _context.SaveChanges();
    }

    private Mock<IFormFile> CreateMockFile(string fileName, long length)
    {
        var mockFile = new Mock<IFormFile>();
        mockFile.Setup(f => f.FileName).Returns(fileName);
        mockFile.Setup(f => f.Length).Returns(length);
        mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>()));
        return mockFile;
    }

    // ========== Index Tests ==========

    [TestMethod]
    public void Index_ReturnsViewWithCourses()
    {
        // Act
        var result = _controller.Index() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as System.Collections.Generic.List<Course>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count);
    }

    // ========== Details Tests ==========

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null);

        // Assert
        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithCourse()
    {
        // Act
        var result = _controller.Details(1050) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Course;
        Assert.IsNotNull(model);
        Assert.AreEqual("Chemistry", model.Title);
    }

    // ========== Create GET Tests ==========

    [TestMethod]
    public void CreateGet_ReturnsViewWithEmptyCourse()
    {
        // Act
        var result = _controller.Create() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsNotNull(result.Model);
        Assert.IsInstanceOfType(result.Model, typeof(Course));
    }

    // ========== Create POST Tests ==========

    [TestMethod]
    public void CreatePost_ValidCourse_NoFile_RedirectsToIndex()
    {
        // Arrange
        var course = new Course
        {
            CourseID = 9999,
            Title = "New Course",
            Credits = 3,
            DepartmentID = 1
        };

        // Act
        var result = _controller.Create(course, null) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(3, _context.Courses.Count());
        var saved = _context.Courses.Find(9999);
        Assert.AreEqual("New Course", saved.Title);
    }

    [TestMethod]
    public void CreatePost_ValidCourse_WithValidImage_RedirectsToIndex()
    {
        // Arrange
        var course = new Course
        {
            CourseID = 8888,
            Title = "Image Course",
            Credits = 4,
            DepartmentID = 1
        };
        var mockFile = CreateMockFile("test.jpg", 1024);

        // Act
        var result = _controller.Create(course, mockFile.Object) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        var saved = _context.Courses.Find(8888);
        Assert.IsNotNull(saved);
        Assert.IsTrue(saved.TeachingMaterialImagePath.StartsWith("/Uploads/TeachingMaterials/"));
        Assert.IsTrue(saved.TeachingMaterialImagePath.EndsWith(".jpg"));
    }

    [TestMethod]
    [DataRow(".txt", DisplayName = "Invalid extension: txt")]
