    [TestInitialize]
    public void Setup()
    {
        TestHelpers.DrainNotificationQueue();
        _context = TestHelpers.CreateInMemoryContext();

        // Create a temp directory for file upload tests
        _tempDir = Path.Combine(Path.GetTempPath(), "CoursesTest_" + Guid.NewGuid().ToString("N"));
        Directory.CreateDirectory(_tempDir);

