        var service = new NotificationService();
        for (int i = 0; i < 15; i++)
        {
            service.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
        }

        // Act
        var result = _controller.GetNotifications() as JsonResult;

        // Assert
        Assert.IsNotNull(result);
        dynamic value = result.Value;
        Assert.IsTrue((bool)value.success);
        Assert.AreEqual(10, (int)value.count);
    }

    [TestMethod]
    public void GetNotifications_Exactly10InQueue_ReturnsAll10()
    {
        // Arrange
