using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;
using System.Collections.Generic;
using System.Reflection;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class NotificationsControllerTests
{
    private SchoolContext _context;
    private NotificationsController _controller;

    [TestInitialize]
    public void Setup()
    {
        TestHelpers.DrainNotificationQueue();
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new NotificationsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
        TestHelpers.DrainNotificationQueue();
    }

    private static object GetProperty(object obj, string name)
    {
        return obj.GetType().GetProperty(name, BindingFlags.Public | BindingFlags.Instance)?.GetValue(obj);
    }

    // ========== GetNotifications Tests ==========

    [TestMethod]
    public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyNotifications()
    {
        // Act
        var result = _controller.GetNotifications() as JsonResult;

        // Assert
        Assert.IsNotNull(result);
        var value = result.Value;
        Assert.IsTrue((bool)GetProperty(value, "success"));
