using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers;

/// <summary>
/// Tests for BaseController functionality.
/// Since BaseController is abstract, we test it through a concrete subclass (HomeController).
/// </summary>
[TestClass]
public sealed class BaseControllerTests
{
    [TestInitialize]
    public void Setup()
    {
        TestHelpers.DrainNotificationQueue();
    }

    [TestCleanup]
    public void Cleanup()
    {
        TestHelpers.DrainNotificationQueue();
    }

    [TestMethod]
    public void Constructor_SetsDbContext()
    {
        // Arrange
        using var context = TestHelpers.CreateInMemoryContext();

        // Act
        using var controller = new HomeController(context);

        // Assert - controller can access db (verified by calling an action that uses it)
        var result = controller.About() as ViewResult;
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void SendEntityNotification_WithDisplayName_EnqueuesNotification()
    {
        // Arrange
        using var context = TestHelpers.CreateInMemoryContext();
        context.Students.Add(new Student
        {
            LastName = "Test",
            FirstMidName = "User",
            EnrollmentDate = new DateTime(2023, 1, 1)
        });
        context.SaveChanges();

        using var controller = new StudentsController(context);

        // Act - Create calls SendEntityNotification with display name
        var student = new Student
        {
            LastName = "Notify",
            FirstMidName = "Me",
            EnrollmentDate = new DateTime(2023, 6, 1)
        };
        controller.Create(student);

        // Assert
        var service = new NotificationService();
        var notifications = new List<Notification>();
        Notification n;
        while ((n = service.ReceiveNotification()) != null) notifications.Add(n);
        Assert.IsTrue(notifications.Any(x =>
            x.EntityType == "Student" &&
            x.Operation == "CREATE" &&
            x.Message.Contains("Me Notify")));
    }

    [TestMethod]
    public void SendEntityNotification_WithoutDisplayName_EnqueuesNotificationWithId()
    {
