            Name = "Test",
            Budget = 100000m,
            StartDate = new DateTime(2010, 1, 1)
        };
        context.Departments.Add(dept);
        context.SaveChanges();

        using var controller = new InstructorsController(context);

        var instructor = new Instructor
        {
            LastName = "TestInst",
            FirstMidName = "NoDisplay",
            HireDate = new DateTime(2023, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };

        // Act
        controller.Create(instructor, null);

        // Assert - notification should use ID-based message (no display name)
        var service = new NotificationService();
        var notifications = new List<Notification>();
        Notification notif;
        while ((notif = service.ReceiveNotification()) != null) notifications.Add(notif);
        Assert.IsTrue(notifications.Any(x =>
            x.EntityType == "Instructor" &&
            x.Operation == "CREATE" &&
