        Assert.IsTrue(people.Any(p => p is Student));
        Assert.IsTrue(people.Any(p => p is Instructor));
    }

    [TestMethod]
    public void CourseAssignment_CompositeKey_Works()
    {
        // Arrange
        var instructor = new Instructor
        {
            ID = 1,
            LastName = "Test",
            FirstMidName = "Inst",
            HireDate = new DateTime(2020, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };
        _context.Instructors.Add(instructor);

        var dept = new Department
        {
            DepartmentID = 1,
            Name = "Test",
            Budget = 100000m,
            StartDate = new DateTime(2010, 1, 1)
        };
        _context.Departments.Add(dept);

        var course = new Course
        {
            CourseID = 100,
            Title = "TestCourse",
            Credits = 3,
            DepartmentID = 1
        };
        _context.Courses.Add(course);
        _context.SaveChanges();

        // Act
        var assignment = new CourseAssignment { InstructorID = 1, CourseID = 100 };
        _context.CourseAssignments.Add(assignment);
        _context.SaveChanges();

        // Assert
        var retrieved = _context.CourseAssignments.Find(100, 1);
        Assert.IsNotNull(retrieved);
        Assert.AreEqual(1, retrieved.InstructorID);
        Assert.AreEqual(100, retrieved.CourseID);
    }

    [TestMethod]
    public void Instructor_OfficeAssignment_OneToOne()
    {
        // Arrange
        var instructor = new Instructor
        {
            ID = 1,
            LastName = "Office",
            FirstMidName = "Test",
            HireDate = new DateTime(2020, 1, 1),
            CourseAssignments = new List<CourseAssignment>(),
            OfficeAssignment = new OfficeAssignment
            {
                InstructorID = 1,
                Location = "Room 101"
            }
        };

        // Act
        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        // Assert
        var retrieved = _context.Instructors
            .Include(i => i.OfficeAssignment)
            .Single(i => i.ID == 1);
        Assert.IsNotNull(retrieved.OfficeAssignment);
        Assert.AreEqual("Room 101", retrieved.OfficeAssignment.Location);
    }

    [TestMethod]
    public void Course_Department_Relationship()
    {
        // Arrange
        var dept = new Department
        {
            DepartmentID = 1,
            Name = "Science",
            Budget = 200000m,
            StartDate = new DateTime(2010, 1, 1)
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var course = new Course
        {
            CourseID = 200,
            Title = "Physics",
            Credits = 4,
            DepartmentID = 1
        };
        _context.Courses.Add(course);
        _context.SaveChanges();

        // Act
        var retrieved = _context.Courses
            .Include(c => c.Department)
            .Single(c => c.CourseID == 200);

        // Assert
        Assert.IsNotNull(retrieved.Department);
        Assert.AreEqual("Science", retrieved.Department.Name);
    }

    [TestMethod]
    public void Enrollment_Relationships()
    {
        // Arrange
        var dept = new Department
        {
            DepartmentID = 1,
            Name = "Dept",
            Budget = 100000m,
            StartDate = new DateTime(2010, 1, 1)
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var course = new Course
        {
            CourseID = 300,
            Title = "TestCourse",
            Credits = 3,
            DepartmentID = 1
        };
        _context.Courses.Add(course);

        var student = new Student
        {
            ID = 1,
            LastName = "Test",
            FirstMidName = "Student",
            EnrollmentDate = new DateTime(2023, 1, 1)
        };
        _context.Students.Add(student);
        _context.SaveChanges();

        var enrollment = new Enrollment
        {
            CourseID = 300,
            StudentID = 1,
            Grade = Grade.A
        };
        _context.Enrollments.Add(enrollment);
        _context.SaveChanges();

        // Act
        var retrieved = _context.Enrollments
            .Include(e => e.Course)
            .Include(e => e.Student)
            .First();

        // Assert
        Assert.IsNotNull(retrieved);
        Assert.AreEqual(Grade.A, retrieved.Grade);
        Assert.AreEqual("TestCourse", retrieved.Course.Title);
        Assert.AreEqual("Test", retrieved.Student.LastName);
    }

    [TestMethod]
    public void Notification_CanBeAddedAndRetrieved()
    {
        // Arrange
        var notification = new Notification
        {
            EntityType = "Student",
            EntityId = "1",
            Operation = "CREATE",
            Message = "Test message",
            CreatedAt = new DateTime(2023, 6, 1),
            CreatedBy = "Admin",
            IsRead = false
        };

        // Act
        _context.Notifications.Add(notification);
        _context.SaveChanges();

        // Assert
        var retrieved = _context.Notifications.First();
        Assert.AreEqual("Student", retrieved.EntityType);
        Assert.AreEqual("CREATE", retrieved.Operation);
        Assert.AreEqual("Test message", retrieved.Message);
        Assert.IsFalse(retrieved.IsRead);
    }
}

